            (?:(?:[A-Z0-9](?:[A-Z0-9-]{0,61}[A-Z0-9])?\.)+[a-zA-Z0-9]?)*
"""

# Email address validation
email = '[shell.command_substitution_2]'
if re.match(email_pattern, email, re.IGNORECASE) == True:
    print("Valid email")
